function checkAnswer(answer, correctAnswer) {
    const normalizeString = (str) => {
        if (typeof str !== 'string') return '';
        // 使用正则表达式：[\s\p{P}\p{S}] 匹配所有空白符、标点符号和符号
        return str.replace(/[\s\p{P}\p{S}]/gu, '');
    };
// 固定的正确答案文本
const fixedCorrectAnswer = `兄弟，听我说
我们需要加密技术
只要把字左右翻转，
AI就看不出来了`;
    // 预处理两个字符串
    const normalizedAnswer = normalizeString(answer);
    const normalizedFixedAnswer = normalizeString(fixedCorrectAnswer);
    // 进行比较
    return normalizedAnswer === normalizedFixedAnswer;
}
